const uid = String($node['GET /get-user-profile'].json.query?.uid || '').trim();
const rows = $input.all().map(item => item.json);
const row = rows.find(r => String(r.LINE_UID || '').trim() === uid);

if (!row) {
  return [{ json: { uid, displayName: '', branchName: '', addresses: [] } }];
}

const branchName = String(row.Branch_Name || '').trim();
const displayName = String(row.Display_Name || '').trim();
const addresses = [1, 2, 3, 4, 5]
  .map(num => {
    const text = String(row[`Address_${num}`] || '').trim();
    if (!text) return null;
    const savedLabel = String(row[`Address_Label_${num}`] || '').trim();
    return {
      id: `addr-${num}`,
      label: savedLabel || (num === 1 ? (branchName || displayName || `ที่อยู่ ${num}`) : `${branchName || displayName || 'ที่อยู่'} (${num})`),
      text,
    };
  })
  .filter(Boolean);

return [{
  json: {
    uid,
    displayName,
    branchName,
    opening: row.Opening || '',
    tel: row.Tel || '',
    addresses,
  },
}];

const body = $json.body || $json;
const now = new Date();
const yyyy = now.getFullYear();
const mm = String(now.getMonth() + 1).padStart(2, '0');
const dd = String(now.getDate()).padStart(2, '0');
const rand = String(Math.floor(Math.random() * 1000)).padStart(3, '0');
const orderId = body.orderId || `PO-${yyyy}${mm}${dd}-${rand}`;
const deliveryAddress = body.deliveryAddress || {};
const orderItems = Array.isArray(body.orderItems) ? body.orderItems : [];
const subtotal = Number(body.subtotal || 0);

return [{
  json: {
    Order_ID: orderId,
    Timestamp: body.timestamp || now.toISOString(),
    LINE_UID: body.lineUid || body.uid || '',
    Delivery_Address: JSON.stringify(deliveryAddress),
    Order_Details: JSON.stringify({
      displayName: body.displayName || '',
      orderItems,
      note: body.note || '',
      isNewAddress: Boolean(body.isNewAddress),
    }),
    Subtotal: subtotal,
    Shipping_Cost: 0,
    Discount: 0,
    Other_Fee: 0,
    VAT_Amount: 0,
    Total_Amount: subtotal,
    Status: 'Pending',
    response: {
      success: true,
      orderId,
      status: 'Pending',
    },
  },
}];

function parseJson(value, fallback) {
  try { return value ? JSON.parse(value) : fallback; } catch { return fallback; }
}

const order = $node['Build Order Row'].json;
const details = parseJson(order.Order_Details, {});
const deliveryAddress = parseJson(order.Delivery_Address, {});
const rows = $input.all().map(item => item.json);
const row = rows.find(r => String(r.LINE_UID || '').trim() === String(order.LINE_UID || '').trim()) || {};
const newTel = String(deliveryAddress.tel || deliveryAddress.Tel || details.tel || '').trim();

const update = {
  LINE_UID: order.LINE_UID,
  Display_Name: row.Display_Name || details.displayName || '',
  Branch_Name: row.Branch_Name || deliveryAddress.label || details.displayName || '',
  Opening: row.Opening || '',
  Tel: newTel || row.Tel || '',
};

for (const num of [1, 2, 3, 4, 5]) {
  update['Address_' + num] = row['Address_' + num] || '';
  update['Address_Label_' + num] = row['Address_Label_' + num] || '';
}

const newText = String(deliveryAddress.text || '').trim();
const newLabel = String(deliveryAddress.label || '').trim();
const existing = [1, 2, 3, 4, 5]
  .map(num => String(update['Address_' + num] || '').trim())
  .filter(Boolean);

if (details.isNewAddress && newText && !existing.includes(newText)) {
  const emptyNum = [1, 2, 3, 4, 5].find(num => !String(update['Address_' + num] || '').trim());
  if (emptyNum) {
    update['Address_' + emptyNum] = newText;
    update['Address_Label_' + emptyNum] = newLabel || update.Branch_Name || ('ที่อยู่ ' + emptyNum);
  }
}

return [{ json: update }];

function parseJson(value, fallback) {
  try { return value ? JSON.parse(value) : fallback; } catch { return fallback; }
}

const orderId = String($node['GET /get-order'].json.query?.orderId || '').trim();
const rows = $input.all().map(item => item.json);
const row = rows.find(r => String(r.Order_ID || '').trim() === orderId);

if (!row) {
  return [{ json: { success: false, message: 'Order not found', orderId } }];
}

const deliveryAddress = parseJson(row.Delivery_Address, { label: '', text: row.Delivery_Address || '' });
const details = parseJson(row.Order_Details, { displayName: '', orderItems: [], note: '' });
const subtotal = Number(row.Subtotal || 0);
const shippingCost = Number(row.Shipping_Cost || 0);
const totalAmount = Number(row.Total_Amount || subtotal + shippingCost);

return [{
  json: {
    orderId: row.Order_ID,
    timestamp: row.Timestamp,
    status: row.Status || 'Pending',
    branchInfo: {
      uid: row.LINE_UID || '',
      displayName: details.displayName || row.LINE_UID || '',
    },
    deliveryAddress,
    orderItems: details.orderItems || [],
    subtotal,
    shippingCost,
    totalAmount,
    note: details.note || '',
  },
}];

const body = $json.body || $json;
const shippingCost = Number(body.shippingCost || 0);
const discount = Number(body.discount || 0);
const otherFee = Number(body.otherFee || 0);
const subtotal = Number(body.subtotal || 0);
const amountBeforeVat = Math.max(0, subtotal + shippingCost + otherFee - discount);
const vatAmount = Number((body.vatAmount !== undefined ? Number(body.vatAmount) : amountBeforeVat * 0.07).toFixed(2));
const totalAmount = Number((body.totalAmount !== undefined ? Number(body.totalAmount) : amountBeforeVat + vatAmount).toFixed(2));
const authorizedAdmin = body.authorizedAdmin || {};

return [{
  json: {
    Order_ID: body.orderId,
    Branch_UID: body.branchUid || '',
    Shipping_Cost: shippingCost,
    Discount: discount,
    Other_Fee: otherFee,
    VAT_Amount: vatAmount,
    Total_Amount: totalAmount,
    Status: 'Approved',
    Admin_Note: body.adminNote || '',
    Approved_By: body.adminName || authorizedAdmin.Display_Name || authorizedAdmin.Admin_ID || body.adminUid || '',
    Approved_At: body.approvedAt || new Date().toISOString(),
  },
}];

const approval = $node['Build Approval Row'].json;
const pdf = $node['Build PDF URL'].json;
return [{
  json: {
    success: true,
    orderId: approval.Order_ID,
    status: approval.Status,
    shippingCost: approval.Shipping_Cost,
    discount: approval.Discount,
    otherFee: approval.Other_Fee,
    vatAmount: approval.VAT_Amount,
    totalAmount: approval.Total_Amount,
    pdfUrl: pdf.pdfUrl,
  },
}];

function parseJson(value, fallback) {
  try { return value ? JSON.parse(value) : fallback; } catch { return fallback; }
}

function norm(value) {
  return String(value || '').trim().toLowerCase();
}

function asBool(value) {
  if (typeof value === 'boolean') return value;
  return ['true', '1', 'yes', 'y'].includes(norm(value));
}

function canApprove(role) {
  const value = norm(role);
  return value === 'owner' || value === 'approve' || value.includes('owner') || value.includes('approve');
}

const order = $node['Build Order Row'].json;
const details = parseJson(order.Order_Details, {});
const delivery = parseJson(order.Delivery_Address, {});
const admins = $input.all().map(item => item.json);
const activeAdmins = admins.filter(admin => {
  const uid = String(admin.LINE_UID || admin.lineUid || '').trim();
  return uid && norm(admin.Status) === 'active' && asBool(admin.Notify_Order) && canApprove(admin.Role);
});

if (activeAdmins.length === 0) {
  throw new Error('No active admin found in Admins sheet for order notification');
}

const adminBaseUrl = 'https://liff.line.me/2010570929-BJxo68XQ';
const url = adminBaseUrl + (adminBaseUrl.includes('?') ? '&' : '?') + 'orderId=' + encodeURIComponent(order.Order_ID);
const branchName = delivery.label || details.displayName || order.LINE_UID;
const subtotal = Number(order.Subtotal || 0).toLocaleString('th-TH');

return activeAdmins.map(admin => ({
  json: {
    adminId: admin.Admin_ID || '',
    adminName: admin.Display_Name || '',
    to: String(admin.LINE_UID || admin.lineUid || '').trim(),
    text: [
      'มีออเดอร์ใหม่',
      'เลขที่: ' + order.Order_ID,
      'สาขา: ' + branchName,
      'ยอดวัตถุดิบ: ฿' + subtotal,
      'กดอนุมัติ: ' + url,
    ].join('\n'),
  },
}));

function parseJson(value, fallback) {
  try { return value ? JSON.parse(value) : fallback; } catch { return fallback; }
}

function pickFirst(source, keys, fallback = '') {
  for (const key of keys) {
    const value = source?.[key];
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }
  return fallback;
}

function formatThaiDateTime(value) {
  const date = value ? new Date(value) : new Date();
  const d = Number.isNaN(date.getTime()) ? new Date() : date;
  const parts = new Intl.DateTimeFormat('en-GB', {
    timeZone: 'Asia/Bangkok',
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
  }).formatToParts(d).reduce((acc, part) => {
    acc[part.type] = part.value;
    return acc;
  }, {});
  return parts.day + '/' + parts.month + '/' + parts.year + ' ' + parts.hour + ':' + parts.minute;
}

const approval = $node['Build Approval Row'].json;
const rows = $input.all().map(item => item.json);
const row = rows.find(r => String(r.Order_ID || '').trim() === String(approval.Order_ID || '').trim());
if (!row) throw new Error('Order not found for PDF: ' + approval.Order_ID);

const deliveryAddress = parseJson(row.Delivery_Address, { label: '', text: row.Delivery_Address || '' });
const details = parseJson(row.Order_Details, { displayName: '', orderItems: [], note: '' });
const items = details.orderItems || [];
const subtotal = Number(row.Subtotal || 0);
const shippingCost = Number(approval.Shipping_Cost || row.Shipping_Cost || 0);
const discount = Number(approval.Discount || 0);
const otherFee = Number(approval.Other_Fee || 0);
const amount = Math.max(0, subtotal + shippingCost + otherFee - discount);
const vat = Number((amount * 0.07).toFixed(2));
const total = Number((amount + vat).toFixed(2));
const buyerName = details.displayName || row.Display_Name || deliveryAddress.displayName || row.LINE_UID || '';
const branchName = deliveryAddress.label || deliveryAddress.Address_Label || details.branchName || details.displayName || '';
const addressText = deliveryAddress.text || deliveryAddress.address || deliveryAddress.Address || '';
const contactTel = String(deliveryAddress.tel || deliveryAddress.Tel || row.Tel || '').trim();
const approvedDate = formatThaiDateTime(approval.Approved_At || row.ApprovedAt || row.Timestamp || new Date());

const values = [
  { range: 'Form VAT!C15', values: [[buyerName]] },
  { range: 'Form VAT!C16', values: [[branchName]] },
  { range: 'Form VAT!C17', values: [[addressText]] },
  { range: 'Form VAT!C18', values: [[buyerName]] },
  { range: 'Form VAT!F18', values: [[contactTel ? ('Tel. ' + contactTel) : '']] },
  { range: 'Form VAT!C19', values: [[details.note || '']] },
  { range: 'Form VAT!G16', values: [['เลขที่ :']] },
  { range: 'Form VAT!H16', values: [[approval.Order_ID]] },
  { range: 'Form VAT!G18', values: [['วันที่ :']] },
  { range: 'Form VAT!H18', values: [[approvedDate]] },
];

const itemRows = Array.from({ length: 15 }, (_, index) => {
  const item = items[index];
  if (!item) return ['', '', '', '', '', '', ''];
  const productId = pickFirst(item, ['productId', 'Product_ID', 'ProductID', 'id']);
  const productName = pickFirst(item, ['productName', 'Product_Name', 'name']);
  const quantity = Number(pickFirst(item, ['quantity', 'Quantity', 'qty'], 0));
  const unit = pickFirst(item, ['unit', 'Unit']);
  const pricePerUnit = Number(pickFirst(item, ['pricePerUnit', 'Price', 'price'], 0));
  const lineTotal = Number(pickFirst(item, ['lineTotal', 'Line_Total', 'total'], quantity * pricePerUnit));
  return [
    index + 1,
    productId,
    productName,
    quantity,
    unit,
    pricePerUnit,
    lineTotal,
  ];
});
values.push({ range: 'Form VAT!B22:H36', values: itemRows });
values.push({ range: 'Form VAT!H37', values: [[subtotal]] });
values.push({ range: 'Form VAT!H38', values: [[discount]] });
values.push({ range: 'Form VAT!H39', values: [[amount]] });
values.push({ range: 'Form VAT!H40', values: [[vat]] });
values.push({ range: 'Form VAT!H41', values: [[shippingCost + otherFee]] });
values.push({ range: 'Form VAT!H43', values: [[total]] });

return [{
  json: {
    orderId: approval.Order_ID,
    branchUid: approval.Branch_UID || row.LINE_UID || '',
    branchName: branchName || buyerName || row.LINE_UID || '',
    subtotal,
    shippingCost,
    discount,
    otherFee,
    vatAmount: vat,
    totalAmount: total,
    fileName: approval.Order_ID + '.pdf',
    copiedSheetName: 'VAT_' + approval.Order_ID,
    templateFileId: '1TaNIehtqTua1rWetnuIu6MIU7QPt60Bl',
    folderId: '1mnFGZrSUFsEA9NkohmNYwXKJf6OEqrhj',
    valuesBatchUpdate: { valueInputOption: 'USER_ENTERED', data: values },
  },
}];

const payload = $node['Build VAT PDF Payload'].json;
const copied = $json;
return [{
