function normalizeStatus(status) {
  return String(status || '').trim().toLowerCase();
}

function isHiddenStatus(status) {
  return ['ยกเลิก', 'cancelled', 'canceled', 'inactive', 'disabled', 'ปิด'].includes(normalizeStatus(status));
}

const rows = $input.all().map(item => item.json);
const products = rows.map((row, index) => {
  const productId = row.Product_ID || row.productId || row.ID || row.id || ('P' + String(index + 1).padStart(3, '0'));
  const productName = row.Product_Name || row.productName || row.Name || row.name || '';
  const price = Number(row.Price || row.price || 0);
  const unit = row.Unit || row.unit || '';
  const imageUrl = row.Image_URL || row.imageUrl || row.Image || row.image || '';
  const status = row.Status || row.status || '';
  return { productId, productName, price, unit, imageUrl, status };
}).filter(product => product.productName && product.price > 0 && !isHiddenStatus(product.status));

return [{ json: { success: true, products } }];

function norm(value) {
  return String(value || '').trim().toLowerCase();
}

function canApprove(role) {
  const value = norm(role);
  return value === 'owner' || value === 'approve' || value.includes('owner') || value.includes('approve');
}

const request = $node['POST /admin-approve'].json;
const body = request.body || request;
const adminUid = String(body.adminUid || '').trim();
if (!adminUid) {
  throw new Error('Missing adminUid. Please open approve page in LINE LIFF and login as admin.');
}

const admins = $input.all().map(item => item.json);
const admin = admins.find(row => String(row.LINE_UID || row.lineUid || '').trim() === adminUid);
if (!admin) {
  throw new Error('This LINE user is not listed in Admins sheet: ' + adminUid);
}
if (norm(admin.Status) !== 'active') {
  throw new Error('This admin is inactive: ' + (admin.Display_Name || adminUid));
}
if (!canApprove(admin.Role)) {
  throw new Error('This admin role cannot approve orders: ' + (admin.Role || ''));
}

return [{
  json: {
    ...body,
    adminUid,
    adminName: body.adminName || admin.Display_Name || admin.Admin_ID || adminUid,
    authorizedAdmin: admin,
  },
}];
